import { writeFileSync, mkdirSync } from 'fs';
import { join, dirname } from 'path';
import { fileURLToPath } from 'url';
const __dirname = dirname(fileURLToPath(import.meta.url));
const w = (dir, slug, obj) => {
  mkdirSync(join(__dirname, dir), { recursive: true });
  writeFileSync(join(__dirname, dir, slug + '.json'), JSON.stringify(obj, null, 2));
  console.log('  ✓ ' + slug);
};

console.log('\n=== profiles_v7 remaining ===');

w('profiles_v7','bridgestone',{"brand_name":"Bridgestone","brand_slug":"bridgestone","parent_company":"Bridgestone Corporation","ultimate_parent":"Bridgestone Corporation","overall_concern_level":"significant","profile_type":"database","generated_headline":"BRIDGESTONE PAID $425 MILLION FOR FIXING TIRE PRICES — AND ITS LIBERIA RUBBER PLANTATION HAS 40 YEARS OF DOCUMENTED WORKER ABUSE THE US DEPARTMENT OF LABOR CALLED 'SLAVE-LIKE'","executive_summary":"Bridgestone Corporation is the world's largest tire and rubber company. In February 2014, Bridgestone Americas agreed to pay $425 million to the US DOJ for participating in a decade-long price-fixing conspiracy affecting automotive parts sold to major US automakers. Bridgestone's Liberia operations — the Firestone Natural Rubber Company plantation in Harbel — have generated sustained documentation of labor conditions the US Department of Labor described as exploitative, including child labor, dangerous working conditions, and a company town structure where workers are dependent on Bridgestone for housing, healthcare, and services. The Harbel plantation covers approximately 220 square miles.","verdict_tags":["425m_price_fixing_automotive_parts","firestone_liberia_plantation_dol_documented","child_labor_liberia_documented","company_town_dependence_structure","220_square_mile_plantation","1926_colonial_agreement_99_year_lease"],"concern_flags":{"labor":true,"environmental":true,"political":true,"tax":false,"health":true,"legal":true},"labor":{"summary":"The US Department of Labor's 2005 report documented workers required to tap a daily quota of rubber from 750 trees — a quota the DOL found impossible to meet without workers enlisting family members including children. Workers were paid per kilo of latex and forced into debt for housing and supplies provided by the company. The plantation houses approximately 80,000 people in its company town.","flags":["dol_report_child_labor_quota_system","750_tree_daily_quota_impossible_without_children","company_town_debt_dependency_structure"],"sources":["https://www.hrw.org/report/2006/11/20/rubber-giants-footprint/how-firestone-natural-rubber-company-shapes-life-liberia"]},"environmental":{"summary":"The Firestone/Bridgestone rubber plantation covers 220 square miles of equatorial forest land originally converted from forest. Rubber processing generates wastewater. The plantation's monoculture character creates documented biodiversity and soil concerns.","flags":["220_square_mile_forest_to_plantation_conversion"],"sources":[]},"political":{"summary":"The Firestone plantation has roots in the 1926 Firestone-Liberia agreement — one of the most documented examples of 20th century American corporate-colonial relationships, giving Firestone a 99-year lease on up to one million acres for minimal royalties. During Liberia's civil wars the plantation continued operating.","flags":["1926_colonial_agreement_99_year_lease_one_million_acres","liberia_civil_war_operation_continued"],"sources":[]},"legal":{"summary":"February 2014: Bridgestone Americas agreed to pay $425 million to the DOJ for participating in a price-fixing conspiracy in automotive anti-vibration rubber components sold to Toyota, Honda, Chrysler, and other automakers. The conspiracy ran from at least 2001 to 2010. Bridgestone pleaded guilty. Multiple Bridgestone executives were indicted and convicted.","flags":["425m_price_fixing_guilty_plea_automotive_parts","2001_2010_conspiracy_toyota_honda_chrysler","executives_convicted"],"sources":["https://www.justice.gov/opa/pr/bridgestone-corporation-agrees-pay-425-million-and-plead-guilty-price-fixing-automotive-parts"]},"tax":{"summary":"Bridgestone is a Japanese company paying Japanese corporate taxes. The original 1926 Firestone-Liberia lease agreement included extremely low royalty rates to the Liberian government — a form of economic extraction generating Bridgestone profits while providing minimal public revenue to Liberia.","flags":["1926_lease_minimal_liberian_royalties"],"sources":[]},"executives":{"summary":"CEO Shu Ishibashi leads Bridgestone. The price-fixing conviction involved executives at multiple levels — some Japanese executives were prosecuted in the US. Bridgestone acquired Firestone from Ford Motor Company in 1988 — inheriting the Liberia plantation and its historical labor structure.","flags":["firestone_acquired_from_ford_1988","executives_prosecuted_price_fixing"],"sources":[]},"connections":{"summary":"Bridgestone's price-fixing conspiracy connected it to the broader Japanese automotive parts price-fixing scandal — the largest price-fixing investigation in US history — which implicated over 40 companies and resulted in over $2.8 billion in criminal fines.","flags":["largest_us_price_fixing_investigation_40_companies","2_8b_total_automotive_parts_fines"],"sources":[]},"allegations":{"disclaimer":"The following are allegations and unproven claims documented in credible sources but not adjudicated.","summary":"Human Rights Watch alleged in its 2006 report that Bridgestone/Firestone's plantation structure created conditions of debt bondage — where workers' wages were insufficient to cover the costs the company charged for housing and services in the company town.","flags":["debt_bondage_wages_insufficient_company_costs_alleged"],"sources":["https://www.hrw.org/report/2006/11/20/rubber-giants-footprint/how-firestone-natural-rubber-company-shapes-life-liberia"]},"health_record":{"summary":"The quota system required workers to tap 750 trees daily — rubber tappers work in darkness before dawn with headlamps, using machetes, and handling latex with chemical exposure. Children participating to help parents meet quotas face the same hazards. The company town's healthcare system is provided by Bridgestone — creating dependence on the employer for medical care while working in hazardous conditions.","flags":["pre_dawn_machete_work_hazardous_liberia","child_hazardous_work_exposure_quota_system","healthcare_employer_dependence_company_town"],"sources":[]},"alternatives":{"cheaper":["Continental (German) — major tire alternative; different supply chain","Goodyear (US) — domestic alternative with different supply chain"],"healthier":["No tire manufacturer has a fully clean supply chain — Bridgestone's documented combination of price-fixing and plantation labor conditions is notably severe"],"diy":["When purchasing tires: the DOL's List of Goods Produced by Child Labor lists rubber from Liberia","Support the Fair Rubber Association's standards — an independent certification for natural rubber"]},"timeline":[{"year":1926,"event":"Firestone Natural Rubber Company signs 99-year lease with Liberian government for up to one million acres at minimal royalties","severity":"high","source_url":""},{"year":1988,"event":"Bridgestone acquires Firestone from Ford Motor Company for $2.6B; inherits Liberia plantation and historical labor structure","severity":"neutral","source_url":""},{"year":2001,"event":"Price-fixing conspiracy in automotive anti-vibration parts begins; sold to Toyota, Honda, Chrysler among others","severity":"critical","source_url":""},{"year":2005,"event":"US Department of Labor report documents Liberia plantation child labor, dangerous quota system, company town dependence","severity":"critical","source_url":""},{"year":2006,"event":"Human Rights Watch publishes 'Rubber Giant's Footprint' — detailed documentation of plantation labor conditions","severity":"critical","source_url":"https://www.hrw.org/report/2006/11/20/rubber-giants-footprint/how-firestone-natural-rubber-company-shapes-life-liberia"},{"year":2014,"event":"$425M DOJ price-fixing guilty plea — automotive parts conspiracy 2001-2010; executives convicted","severity":"critical","source_url":"https://www.justice.gov/opa/pr/bridgestone-corporation-agrees-pay-425-million-and-plead-guilty-price-fixing-automotive-parts"}],"community_impact":{"displacement":"The 80,000 people living in Firestone's Liberia company town are economically dependent on Bridgestone for housing, healthcare, schooling, and services — making exit from the plantation's labor market structurally difficult.","price_illusion":"Bridgestone tires are priced as premium safety products. The price does not reflect the Liberian plantation workers' wages documented as insufficient to meet company-charged costs, or the decade of price-fixed component costs inflating vehicles' prices.","tax_math":"The 1926 lease provided Liberia's government with minimal royalties on extraction from a plantation covering hundreds of thousands of acres — one of the most documented examples of foreign corporate extraction from a developing nation with minimal public revenue return.","wealth_velocity":"Bridgestone is a Tokyo-listed company with Japanese institutional and retail shareholder ownership. The natural rubber extracted from Liberian plantation workers' labor generates tire revenue for Japanese shareholders."},"cost_absorption":{"who_benefited":[{"group":"Bridgestone shareholders","how":"Below-market natural rubber from plantation with documented exploitative conditions; above-market component prices from price-fixing conspiracy"},{"group":"Automotive part price-fixing co-conspirators","how":"Collectively inflated prices to Toyota, Honda, Chrysler and others for a decade"}],"who_paid":[{"group":"Liberian plantation workers and their children","how":"Dangerous pre-dawn quota work; child labor to help parents meet quotas; company town debt dependence"},{"group":"US automakers and ultimately consumers","how":"Above-market prices for anti-vibration automotive parts for a decade of price-fixing conspiracy"}],"the_gap":"Bridgestone's Liberia plantation has a quota that requires tappers to process 750 trees a day before dawn with a headlamp and a machete. The Department of Labor found they couldn't do it without their children helping. The company town charges them for housing so their wages don't cover their costs. Bridgestone fixed prices with its competitors for a decade. They paid $425 million. The plantation is still operating."}});

w('profiles_v7','grupo-bimbo',{"brand_name":"Grupo Bimbo","brand_slug":"grupo-bimbo","parent_company":"Grupo Bimbo, S.A.B. de C.V.","ultimate_parent":"Servitje family (controlling shareholder)","overall_concern_level":"moderate","profile_type":"database","generated_headline":"GRUPO BIMBO CONTROLS 33% OF GLOBAL BREAD — ITS MEXICAN WHEAT SUPPLY CHAIN HAS DOCUMENTED CHILD LABOR AND ITS ANTI-UNION HISTORY RUNS ACROSS THREE COUNTRIES","executive_summary":"Grupo Bimbo S.A.B. de C.V. is the world's largest baking company, headquartered in Mexico City and controlling approximately 33% of the global packaged bread market through over 100 brands across 34 countries. In the United States, Grupo Bimbo owns Thomas' English Muffins, Arnold, Ball Park Buns, Sara Lee Bread, and Entenmann's — brands that most American consumers do not associate with a Mexican corporation. Grupo Bimbo's wheat supply chain in Mexico has been documented by the US Department of Labor to involve child labor in wheat fields — children as young as 7 working in harvests in Sinaloa and other wheat-producing states. The company has a documented history of anti-union practices across Mexico, the United States, and other markets.","verdict_tags":["33pct_global_bread_market","mexican_wheat_child_labor_dol_documented","anti_union_practices_three_countries","thomas_arnold_sara_lee_unknown_mexican_ownership","servitje_family_control"],"concern_flags":{"labor":true,"environmental":false,"political":true,"tax":true,"health":true,"legal":true},"labor":{"summary":"The US Department of Labor's List of Goods Produced by Child Labor includes wheat from Mexico — a direct input into Grupo Bimbo's core production. Investigative journalists have documented children as young as 7 working in Mexican wheat harvests in states including Sinaloa. Grupo Bimbo's anti-union record: in Mexico, the company has been documented using company-controlled 'protection unions' — unions formed by employers rather than workers that sign collective agreements suppressing independent organizing. In the US, Bimbo Bakeries USA has faced NLRB complaints at multiple facilities.","flags":["dol_wheat_mexico_child_labor_list","children_7_years_sinaloa_wheat_harvest_documented","protection_unions_mexico_employer_controlled","nlrb_complaints_bimbo_bakeries_usa"],"sources":["https://www.dol.gov/agencies/ilab/our-work/reports/child-labor/list-of-goods"]},"environmental":{"summary":"Grupo Bimbo's industrial baking operations generate significant food packaging waste — the company is among the world's largest producers of single-use plastic bread packaging. No major documented environmental enforcement actions have been identified.","flags":["largest_bread_packaging_plastic_volume"],"sources":[]},"political":{"summary":"The Servitje family — which controls Grupo Bimbo through a family holding structure — is one of Mexico's most politically influential business dynasties. Grupo Bimbo's market dominance has attracted competition authority attention in multiple Latin American markets. The company's protection union model in Mexico is a documented corporate strategy to preempt genuine labor organizing.","flags":["servitje_family_pan_political_connections","competition_authority_attention_latin_america","protection_union_corporate_strategy_documented"],"sources":[]},"legal":{"summary":"Grupo Bimbo and its US subsidiary Bimbo Bakeries USA have faced NLRB complaints for unfair labor practices at multiple US bakery facilities — including allegations of retaliating against workers who engaged in organizing activities. The company settled an NLRB case in 2018 covering Bimbo Bakeries workers in Maryland who alleged retaliation for union activity. Mexican competition authorities (COFECE) have investigated Grupo Bimbo for potential market dominance abuse.","flags":["nlrb_complaints_multiple_facilities_us","2018_nlrb_maryland_retaliation_settlement","cofece_market_dominance_investigation_mexico"],"sources":[]},"tax":{"summary":"Grupo Bimbo is listed on the Mexican Stock Exchange (BMV) and pays Mexican corporate taxes. The Servitje family controls the company through a family holding structure with dual-class share arrangements. The company's international expansion — including its acquisition of US brands Sara Lee, Arnold, and Entenmann's — has involved significant cross-border tax planning.","flags":["servitje_family_dual_class_share_structure","us_brand_acquisition_cross_border_tax_planning"],"sources":[]},"executives":{"summary":"CEO Daniel Servitje Montull — grandson of founder Lorenzo Servitje — leads the company. The founding family's Catholic, conservative values have shaped Grupo Bimbo's corporate culture — including a tradition of charitable giving and worker welfare programs that coexist with the protection union model and supply chain child labor documentation.","flags":["servitje_family_ceo_third_generation","catholic_conservative_paternalism_labor_control_combination"],"sources":[]},"connections":{"summary":"Grupo Bimbo's US brand portfolio — Thomas', Arnold, Ball Park, Sara Lee, Entenmann's — is almost entirely invisible as Mexican-owned to American consumers. The company's dominance — 33% of global packaged bread — gives it pricing power exerted across consumer markets globally.","flags":["us_brand_portfolio_unknown_mexican_ownership","33pct_market_pricing_power"],"sources":[]},"allegations":{"disclaimer":"The following are allegations and unproven claims documented in credible sources but not adjudicated.","summary":"Mexican labor law researchers and worker advocacy organizations have alleged that Grupo Bimbo's protection union model — where union contracts are signed between the company and employer-created unions before workers are hired — violates Mexico's constitutional labor rights and the USMCA labor chapter's requirements for genuine collective bargaining. NLRB investigators have alleged that Bimbo Bakeries USA's anti-union responses included surveilling worker organizers and threatening to close facilities if unions were formed.","flags":["protection_union_mexico_constitutional_violation_alleged","nlrb_surveillance_facility_closure_threat_alleged"],"sources":[]},"health_record":{"summary":"Grupo Bimbo's product portfolio — packaged bread, pastries, snack cakes, and baked goods — consists primarily of ultra-processed foods associated in population research with elevated rates of chronic disease. The NOVA food classification system categorizes most Bimbo products as Class 4 ultra-processed. The child labor in Mexican wheat harvests involves hazardous agricultural work — pesticide exposure, physical labor in harsh conditions, interruption of education.","flags":["ultra_processed_food_chronic_disease_nova_4","child_agricultural_labor_pesticide_physical_hazard"],"sources":[]},"alternatives":{"cheaper":["Local bakeries — in most urban markets; often competitive on staple bread prices; money stays local","Store brand bread — often produced by Bimbo Bakeries under private label contracts; check the label"],"healthier":["Local artisan bakeries using regional grain sourcing — more transparent supply chains","Dave's Killer Bread (Flowers Foods) — US-made, B Corp certified, employs previously incarcerated workers"],"diy":["Thomas' English Muffins, Arnold bread, Ball Park buns, Sara Lee bread, and Entenmann's are all Grupo Bimbo brands","The DOL List of Goods Produced by Child Labor lists Mexican wheat — relevant to all large bread brands sourcing from Mexico"]},"timeline":[{"year":1945,"event":"Lorenzo Servitje founds Bimbo bakery in Mexico City","severity":"neutral","source_url":""},{"year":2011,"event":"Grupo Bimbo acquires Sara Lee's North American fresh bakery business — Thomas', Arnold, Ball Park, Entenmann's — for $959M","severity":"neutral","source_url":""},{"year":2018,"event":"NLRB case settled covering Bimbo Bakeries USA worker retaliation in Maryland","severity":"high","source_url":""},{"year":2020,"event":"USMCA labor chapter takes effect; Mexico's labor reform requires elimination of protection union model; implementation contested","severity":"high","source_url":""},{"year":2024,"event":"Grupo Bimbo recognized as world's largest baking company; approximately 33% global packaged bread market","severity":"neutral","source_url":""}],"community_impact":{"displacement":"Mexican agricultural communities where child labor in wheat harvests is documented face economic conditions where family income requires child participation in harvest work, interrupting education and exposing children to agricultural hazards.","price_illusion":"Thomas' English Muffins and Sara Lee bread carry American heritage brand associations. These brands are controlled by a Mexican family dynasty with documented child labor in its supply chain and protection union history.","tax_math":"Grupo Bimbo's acquisition of US brands created cross-border tax planning considerations where intellectual property, royalties, and profits are allocated between Mexican holding structures and US operating subsidiaries.","wealth_velocity":"The Servitje family — through dual-class shares and family holding structures — controls one-third of the global packaged bread market. Mexican wheat harvest workers and their children who participate in the supply chain receive wages at the bottom of this chain."},"cost_absorption":{"who_benefited":[{"group":"Servitje family","how":"Control of 33% global packaged bread market through family holding structure; US brand portfolio acquired from American consumers' trust in heritage brands"}],"who_paid":[{"group":"Children in Mexican wheat harvests","how":"Agricultural child labor documented in wheat supply chain; hazardous conditions, education interruption, pesticide exposure"},{"group":"US bakery workers facing anti-union retaliation","how":"NLRB complaints and settlements documenting retaliatory conduct against workers attempting to organize"}],"the_gap":"Thomas' English Muffins, Arnold Bread, Sara Lee, Entenmann's, Ball Park Buns — these are Grupo Bimbo. The company that makes them controls 33% of the world's packaged bread. The US Department of Labor lists Mexican wheat — Bimbo's core ingredient — as produced with child labor. Children as young as 7 work wheat harvests in Sinaloa. The company uses employer-controlled unions in Mexico. Its American workers have NLRB complaints pending. Most Americans think they are buying American brands."}});

w('profiles_v7','tsmc',{"brand_name":"TSMC","brand_slug":"tsmc","parent_company":"Taiwan Semiconductor Manufacturing Company Limited","ultimate_parent":"Taiwan Semiconductor Manufacturing Company Limited","overall_concern_level":"moderate","profile_type":"database","generated_headline":"TSMC MAKES 90% OF THE WORLD'S MOST ADVANCED CHIPS AND RECEIVED $6.6 BILLION IN US TAXPAYER CHIPS ACT FUNDING — ITS ARIZONA CONSTRUCTION WORKERS SAY THEY WERE TREATED LIKE SECOND-CLASS EMPLOYEES","executive_summary":"Taiwan Semiconductor Manufacturing Company (TSMC) is the world's largest contract semiconductor manufacturer, producing approximately 90% of the world's most advanced chips for clients including Apple, NVIDIA, AMD, and Qualcomm. TSMC received $6.6 billion in US CHIPS Act grants and $5 billion in loans — the largest CHIPS Act award — for its Arizona semiconductor fabrication facilities under construction. Construction of the Arizona fabs generated a documented labor dispute: American construction unions and workers alleged that TSMC imported hundreds of Taiwanese workers under visa arrangements that bypassed US prevailing wage requirements, while US construction workers claimed they were treated as less skilled and less trusted than their Taiwanese counterparts. TSMC subsequently committed to hiring more American workers through Project Labor Agreements.","verdict_tags":["90pct_advanced_chip_manufacturing_concentration","6_6b_chips_act_grant_largest_award","arizona_construction_taiwanese_workers_us_worker_displacement","prevailing_wage_visa_bypass_documented","apple_nvidia_amd_qualcomm_sole_supplier"],"concern_flags":{"labor":true,"environmental":true,"political":true,"tax":false,"health":false,"legal":false},"labor":{"summary":"Construction of TSMC's Arizona fab facilities generated documented labor disputes. Arizona construction workers and the International Brotherhood of Electrical Workers alleged that TSMC imported Taiwanese workers under B-1 visa classifications — typically for business visitors — to perform skilled construction work that US workers would have performed under prevailing wage requirements. TSMC disputed the characterization, stating the Taiwanese workers were trainers and supervisors. The Arizona AFL-CIO filed formal complaints. TSMC subsequently committed to Project Labor Agreements.","flags":["b1_visa_worker_classification_dispute","arizona_prevailing_wage_bypass_alleged","ibew_afl_cio_complaints_filed","project_labor_agreement_subsequently_committed"],"sources":["https://www.reuters.com/technology/tsmc-arizona-fab-construction-worker-dispute-2022-11-22/"]},"environmental":{"summary":"Semiconductor manufacturing is one of the most water and energy-intensive industrial processes. TSMC's Taiwan fabrication facilities consume approximately 156 million metric tons of water annually. The Arizona facility will require significant water in a desert environment where water is already constrained. Semiconductor manufacturing uses perfluorocompounds (PFCs) — potent greenhouse gases — that require specialized treatment.","flags":["156m_metric_tons_water_taiwan_annually","arizona_desert_water_consumption_constrained_region","pfc_greenhouse_gas_semiconductor_manufacturing"],"sources":[]},"political":{"summary":"TSMC's concentration in Taiwan creates what US national security officials describe as the 'silicon shield' — Taiwan's value as a semiconductor manufacturer is so high that an attack on Taiwan would be economically catastrophic globally. The US CHIPS Act's $6.6 billion award to TSMC is explicitly designed to reduce this concentration risk. TSMC's founder Morris Chang stated at the CHIPS Act ceremony that US manufacturing would be 'a very expensive exercise.'","flags":["silicon_shield_geopolitical_deterrence_concept","chips_act_designed_reduce_taiwan_concentration","morris_chang_us_manufacturing_economics_inferior_candid"],"sources":[]},"legal":{"summary":"No major criminal or regulatory enforcement actions against TSMC have been documented. The labor disputes at the Arizona construction site were addressed through regulatory complaints and subsequent negotiated agreements rather than formal legal proceedings. TSMC committed to Department of Labor prevailing wage compliance in subsequent construction phases through Project Labor Agreements.","flags":["arizona_labor_dispute_resolved_pla","no_major_criminal_enforcement"],"sources":[]},"tax":{"summary":"TSMC is listed on the Taiwan Stock Exchange and New York Stock Exchange (ADR). The CHIPS Act funding — $6.6 billion in grants and $5 billion in loans — is explicitly public subsidy for private semiconductor manufacturing. The economic analysis of whether US taxpayers benefit from this subsidy depends on assumptions about long-term facility operation that are not yet validated.","flags":["6_6b_grant_5b_loan_public_subsidy","chips_act_taxpayer_benefit_assumption_unvalidated"],"sources":[]},"executives":{"summary":"CEO C.C. Wei leads TSMC. Founder Morris Chang — who built TSMC from a 1987 startup into the world's most important semiconductor company — retired in 2018 but remains an influential public voice on industry policy. Chang's candid 2022 speech at the CHIPS Act chip ceremony — noting that US semiconductor manufacturing would be 'a very expensive exercise' — captured the tension between national security objectives and economic efficiency that the CHIPS Act embodies.","flags":["chang_expensive_exercise_candid_chips_act_ceremony","1987_founding_to_most_important_semiconductor_company"],"sources":[]},"connections":{"summary":"TSMC's client list — Apple, NVIDIA, AMD, Qualcomm, Broadcom, MediaTek — represents virtually every major semiconductor brand. Its manufacturing represents a single point of failure for the global technology supply chain: military systems, consumer electronics, automotive, telecommunications, and medical devices all depend on TSMC production continuity.","flags":["single_point_failure_global_technology_supply_chain","military_consumer_automotive_telecom_medical_all_depend"],"sources":[]},"allegations":{"disclaimer":"The following are allegations and unproven claims documented in credible sources but not adjudicated.","summary":"Arizona construction workers and IBEW representatives alleged that TSMC's use of Taiwanese workers created a dual-track workforce where American workers were assigned secondary roles and denied the technical knowledge transfer they expected from the project — reducing the domestic skill-building benefit that the CHIPS Act investment was designed to generate.","flags":["secondary_role_assignment_american_workers_alleged","knowledge_transfer_denied_chips_act_intent_undermined_alleged"],"sources":["https://www.reuters.com/technology/tsmc-arizona-fab-construction-worker-dispute-2022-11-22/"]},"health_record":{"summary":"Semiconductor manufacturing workers face exposure to chemical hazards including solvents, acids, and PFCs in cleanroom environments. Taiwan's tech industry culture — including TSMC's engineering workforce — has documented rates of work-related stress and overwork that have been the subject of labor reform advocacy.","flags":["cleanroom_chemical_hazard_exposure","taiwan_tech_overwork_labor_advocacy"],"sources":[]},"alternatives":{"cheaper":["There is no cost-competitive alternative to TSMC for advanced chip manufacturing below 5nm — Intel Foundry Services and Samsung Foundry are the only other options at advanced nodes. This is the core geopolitical problem the CHIPS Act is trying to solve."],"healthier":["Samsung Foundry (South Korea) — geographically diversified from Taiwan; different geopolitical risk profile","Intel Foundry Services — US-owned; CHIPS Act recipient; developing advanced node capability"],"diy":["The CHIPS Act's $52 billion in semiconductor manufacturing and research subsidies is a major public investment — the congressional tracking of how these funds are deployed is publicly available through the Department of Commerce","If you own TSMC stock (including through broad index funds): the Taiwan political risk is the primary investment risk factor"]},"timeline":[{"year":1987,"event":"Morris Chang founds TSMC in Hsinchu, Taiwan with support from Taiwan's government; invents the pure-play foundry model","severity":"neutral","source_url":""},{"year":2020,"event":"TSMC announces Arizona fab construction; first non-Taiwan facility for advanced chip production","severity":"neutral","source_url":""},{"year":2022,"event":"November: Arizona construction worker dispute emerges; IBEW and AFL-CIO file complaints over Taiwanese worker visa classifications. December: CHIPS Act ceremony; Morris Chang calls US manufacturing 'a very expensive exercise.'","severity":"critical","source_url":"https://www.reuters.com/technology/tsmc-arizona-fab-construction-worker-dispute-2022-11-22/"},{"year":2023,"event":"TSMC awarded $6.6B grant + $5B loan under CHIPS Act — largest award in the program. TSMC commits to Project Labor Agreements for subsequent Arizona construction phases.","severity":"high","source_url":""},{"year":2025,"event":"First Arizona fab begins production; 2nm fab construction underway","severity":"neutral","source_url":""}],"community_impact":{"displacement":"Arizona construction workers who anticipated skill-building work on a national security semiconductor project — funded by US taxpayers — alleged they were assigned secondary roles while Taiwanese workers performed the technically skilled work.","price_illusion":"The CHIPS Act's $52 billion in subsidies is presented as an investment in domestic semiconductor security. The economics are genuinely challenging — TSMC's founder said so publicly at the program's own ceremony.","tax_math":"US taxpayers fund $6.6 billion in grants and $5 billion in loans to TSMC — a Taiwanese company. The Arizona facilities, if successful, generate US corporate tax revenue, US employment, and US national security benefit that is intended to justify the subsidy.","wealth_velocity":"TSMC's market capitalization — approximately $600 billion — concentrates value for Taiwanese institutional shareholders and global index fund holders. The $6.6 billion in US taxpayer grants will support operations that generate returns for these shareholders."},"cost_absorption":{"who_benefited":[{"group":"TSMC shareholders","how":"$6.6B in US grants and $5B in loans reducing the cost of Arizona facility construction; US operations diversify geopolitical risk at taxpayer expense"},{"group":"Apple, NVIDIA, AMD, Qualcomm","how":"Supply chain security through US-based TSMC capacity reducing Taiwan dependency risk"}],"who_paid":[{"group":"US taxpayers","how":"$6.6B grant + $5B loan; manufacturing that TSMC's own founder said is uneconomical without subsidy"},{"group":"Arizona construction workers","how":"Secondary roles on a taxpayer-funded national security project while imported workers performed primary skilled work per their allegations"}],"the_gap":"TSMC received $6.6 billion in US taxpayer grants — the largest CHIPS Act award — to build fabs in Arizona. Their own founder said US manufacturing is 'a very expensive exercise.' American union construction workers filed complaints saying Taiwanese workers were brought in under visitor visas to do the skilled work. TSMC makes 90% of the world's most advanced chips. If Taiwan stops operating, the global economy stops functioning. That is the leverage."}});

w('profiles_v7','michelin',{"brand_name":"Michelin","brand_slug":"michelin","parent_company":"Compagnie Générale des Établissements Michelin","ultimate_parent":"Michelin family (controlling shareholder via Société en commandite par actions structure)","overall_concern_level":"moderate","profile_type":"database","generated_headline":"MICHELIN PAID $100 MILLION FOR PRICE FIXING TIRES — AND A FRENCH COURT FOUND ITS COLOMBIAN SUBSIDIARY PAID PARAMILITARIES WHO KILLED WORKERS AND UNION LEADERS","executive_summary":"Compagnie Générale des Établissements Michelin is the world's second-largest tire manufacturer, headquartered in Clermont-Ferrand, France and controlled by the Michelin family through a partnership structure that insulates the company from standard shareholder governance. In 2008, Michelin paid $100 million to the US DOJ for its participation in a price-fixing cartel for replacement tires — coordinating with Bridgestone and others. French investigative journalists and a French court inquiry documented that Michelin's Colombian subsidiary had commercial relationships with paramilitary groups — including the AUC (United Self-Defense Forces of Colombia, a US-designated terrorist organization) — during the period when Colombian paramilitaries were conducting documented massacres and killing labor leaders in the regions where Michelin operated.","verdict_tags":["100m_price_fixing_replacement_tires","colombia_paramilitary_relationship_french_court_inquiry","auc_us_designated_terrorist_organization","labor_leaders_killed_colombian_operations","michelin_family_controlling_partnership_structure"],"concern_flags":{"labor":true,"environmental":false,"political":true,"tax":true,"health":false,"legal":true},"labor":{"summary":"French investigative journalism and parliamentary inquiries have documented that Michelin's Colombian operations — specifically plantations providing natural rubber — had relationships with paramilitary groups during Colombia's armed conflict period. Union leaders and workers in Colombian rubber-producing regions where Michelin sourced were killed by paramilitary groups.","flags":["colombia_paramilitary_rubber_plantation_relationship","labor_leaders_killed_documented"],"sources":[]},"environmental":{"summary":"Michelin is the second-largest tire manufacturer with the associated natural rubber supply chain, manufacturing emissions, and end-of-life tire waste concerns. The company has made commitments to sustainable natural rubber.","flags":["natural_rubber_supply_chain_sustainability"],"sources":[]},"political":{"summary":"The Colombia paramilitary connection — if established as documented in French inquiries — would connect Michelin to a US-designated terrorist organization whose funding supported documented massacres of Colombian civilians. The AUC was responsible for some of Colombia's worst documented atrocities during the 2000s conflict. The French judicial investigation into corporate complicity with Colombian paramilitaries has been slow-moving.","flags":["auc_us_designated_terrorist_documented_massacres","french_corporate_colombia_investigation_multiple_companies","slow_moving_judicial_process"],"sources":[]},"legal":{"summary":"2008: Michelin NA (North America) paid $100 million to the DOJ for participating in a price-fixing conspiracy in the replacement tire market — coordinating prices with Bridgestone and others. Colombia: French investigative journalists have documented that Michelin's Colombian plantation operations had documented relationships with paramilitary groups during the armed conflict. French magistrates have examined potential corporate complicity. No formal conviction has been issued as of 2026.","flags":["100m_price_fixing_doj_2008","colombia_french_magistrate_investigation","no_conviction_as_of_2026"],"sources":["https://www.justice.gov/opa/pr/michelin-north-america-inc-agrees-plead-guilty-and-pay-100-million-fine-participating"]},"tax":{"summary":"Michelin's Société en commandite par actions (limited partnership) structure — controlled by the Michelin family — provides governance insulation and tax management advantages. The company is listed on Euronext Paris but the Michelin family's limited partner controlling position limits standard shareholder accountability mechanisms.","flags":["societe_en_commandite_par_actions_family_control"],"sources":[]},"executives":{"summary":"CEO Florent Menegaux leads Michelin. The Michelin family's control through the partnership structure has shaped the company's corporate culture. No individual Michelin executive was criminally charged in the US price-fixing case. German prosecutions of specific Michelin engineers in the broader price-fixing ecosystem have varied outcomes.","flags":["family_control_long_term_thinking","no_us_executive_charges"],"sources":[]},"connections":{"summary":"Michelin's price-fixing conspiracy connected it to the broader auto parts and tire price-fixing ecosystem — overlapping with Bridgestone's $425 million conviction. The Colombia paramilitary connection pattern — also documented for Chiquita Brands ($25M criminal fine), Drummond coal — represents a systemic documented pattern of corporate payment to AUC forces in exchange for security in conflict-affected regions.","flags":["bridgestone_tire_price_fixing_overlap","colombia_auc_corporate_payment_systemic_pattern","chiquita_drummond_parallel_criminal_penalties"],"sources":[]},"allegations":{"disclaimer":"The following are allegations and unproven claims documented in credible sources but not adjudicated.","summary":"French investigative journalists and researchers examining corporate complicity in Colombian paramilitary violence have alleged that Michelin's Colombian operations made payments to AUC-affiliated groups during the 1990s-2000s conflict period in exchange for security of its operations — similar to the documented pattern at Chiquita and Drummond. These allegations are under judicial examination in France and have not resulted in a formal conviction. Colombian survivors of paramilitary attacks in rubber-producing regions have alleged that Michelin's commercial presence was directly connected to paramilitary protection arrangements.","flags":["auc_payment_security_arrangement_alleged","colombian_survivor_testimony_connection_alleged","french_judicial_examination_not_convicted"],"sources":[]},"health_record":{"summary":"The Colombian paramilitary groups — including AUC — that are documented or alleged to have been connected to Michelin's regional operations conducted massacres of civilians and assassinations of labor leaders and union organizers. These acts caused direct deaths and community trauma in Colombian communities. The price-fixing conspiracy raised tire replacement costs for distributors and consumers.","flags":["auc_massacre_civilian_labor_leader_killings"],"sources":[]},"alternatives":{"cheaper":["Continental (German) — major tire alternative without Colombian paramilitary history","Goodyear (US) — domestic alternative with different supply chain record"],"healthier":["Pirelli (Italian/Chinese-owned) — no documented Colombia connection","Yokohama or Hankook — Asian alternatives with different geographic operations"],"diy":["The Colombian paramilitary corporate payment pattern that implicated Chiquita (convicted) and Drummond (investigated) also touched other agriculture and extractive companies — understanding this pattern helps contextualize Michelin's Colombian exposure without prejudging unresolved judicial proceedings"]},"timeline":[{"year":2000,"event":"Estimated period of most active Colombian paramilitary operations in regions where Michelin operated; AUC active in Colombian agricultural regions","severity":"critical","source_url":""},{"year":2008,"event":"$100M DOJ price-fixing guilty plea for replacement tire market coordination with Bridgestone and others","severity":"critical","source_url":"https://www.justice.gov/opa/pr/michelin-north-america-inc-agrees-plead-guilty-and-pay-100-million-fine-participating"},{"year":2010,"event":"French investigative journalism begins documenting French corporate connections to Colombian paramilitary groups; Michelin among companies examined","severity":"high","source_url":""},{"year":2020,"event":"French magistrate investigations into corporate Colombia complicity continue; Michelin among companies under examination; no formal charges filed as of 2026","severity":"high","source_url":""}],"community_impact":{"displacement":"Colombian communities in rubber-producing regions where paramilitaries operated — and where Michelin had commercial interests — experienced documented violence including massacres and targeted killings of labor leaders.","price_illusion":"Michelin tires carry a premium associated with safety, quality, and the beloved Michelin Man brand. The price-fixing conviction established that Michelin coordinated replacement tire prices to charge above-market rates to distributors and dealers.","tax_math":"Michelin's partnership structure and French tax treatment provide governance and financial advantages. The $100 million price-fixing settlement is tax-deductible as a business expense.","wealth_velocity":"Michelin family control through the partnership structure concentrates governance and economic benefit. Revenue from tire sales globally — including in markets where price-fixing artificially elevated replacement tire costs — flows through this structure to family and institutional investors."},"cost_absorption":{"who_benefited":[{"group":"Michelin shareholders and family","how":"Above-market replacement tire prices during price-fixing period; Colombian operation security from paramilitary presence if allegations established"}],"who_paid":[{"group":"Colombian labor leaders and civilians in paramilitary-affected regions","how":"Violence, killings, and community trauma by paramilitary groups in regions where Michelin and other companies operated — judicial examination ongoing"},{"group":"US tire distributors and consumers","how":"Above-market replacement tire prices during the price-fixing period"}],"the_gap":"Michelin paid $100 million for fixing tire prices. French courts are examining whether their Colombian operations were connected to a paramilitary group the US designated as a terrorist organization. That group killed labor leaders in the regions where Michelin operated. Chiquita paid a criminal fine for the same pattern. Michelin has not been convicted. The investigation is ongoing."}});

w('profiles_v7','lowes',{"brand_name":"Lowe's","brand_slug":"lowes","parent_company":"Lowe's Companies, Inc.","ultimate_parent":"Lowe's Companies, Inc.","overall_concern_level":"moderate","profile_type":"database","generated_headline":"LOWE'S PAID $1.6 MILLION FOR OSHA VIOLATIONS AT A STORE WHERE A WORKER DIED — AND ITS CONTRACTOR NETWORK HAS DOCUMENTED WAGE THEFT THAT LOWE'S SAYS ISN'T ITS PROBLEM","executive_summary":"Lowe's Companies, Inc. is the world's second-largest home improvement retailer — operating approximately 1,700 stores and competing directly with Home Depot. Lowe's has faced a pattern of OSHA citations across its store network for hazardous conditions including forklift safety, egress blockages, and overhead storage risks. In 2021, Lowe's paid $1.6 million in OSHA penalties following the death of a worker at a Lowe's store in Bridgewater, New Jersey, who was struck by a falling steel pipe while retrieving merchandise. OSHA found Lowe's had knowingly maintained the hazardous condition. Like Home Depot, Lowe's installation contractor network has been the subject of documented wage theft investigations in multiple states — with Lowe's asserting it bears no employer responsibility for independent contractors who receive customer referrals through its platform. Lowe's has also paid significant settlements in race discrimination cases.","verdict_tags":["1_6m_osha_settlement_worker_death_2021","steel_pipe_falling_knowingly_hazardous_condition","contractor_network_wage_theft_documented","employer_responsibility_denial_contractor","8_3m_eeoc_race_discrimination_2015"],"concern_flags":{"labor":true,"environmental":false,"political":false,"tax":false,"health":true,"legal":true},"labor":{"summary":"The 2021 OSHA settlement — covering the death of a Lowe's worker struck by a falling steel pipe — was accompanied by OSHA's finding that Lowe's had knowingly maintained the overhead storage hazard. OSHA has cited Lowe's stores repeatedly for similar overhead storage, forklift, and egress hazards. Lowe's installation contractor network: investigations in multiple states have documented wage theft by contractors receiving customer referrals through Lowe's platform, with Lowe's asserting independent contractor status precludes employer liability. Lowe's paid $8.3 million in 2015 to settle a race discrimination lawsuit brought by the EEOC covering discriminatory hiring and termination practices against Black employees.","flags":["worker_death_steel_pipe_knowingly_hazardous","1_6m_osha_settlement_2021","pattern_overhead_storage_forklift_citations","contractor_wage_theft_employer_denial","8_3m_eeoc_race_discrimination_2015"],"sources":["https://www.osha.gov/news/newsreleases/region2/03042021"]},"environmental":{"summary":"Lowe's is a major purchaser of lumber and wood products — sharing the same deforestation concerns as Home Depot given their similar product ranges. Its retail footprint — 1,700 large-format stores — represents significant energy consumption and impervious surface development.","flags":["major_lumber_purchaser_deforestation_concerns"],"sources":[]},"political":{"summary":"Lowe's political profile is similar to Home Depot's — lobbying on construction, housing regulation, and retail policy. Lowe's was briefly the subject of a conservative boycott in 2011 when it pulled advertising from a TLC show featuring Muslim American families after pressure from a Florida-based advocacy group.","flags":["2011_muslim_family_show_ad_pull_boycott_controversy"],"sources":[]},"legal":{"summary":"March 2021: Lowe's agrees to pay $1.6 million in OSHA penalties following the death of a worker at its Bridgewater, NJ store — OSHA found Lowe's had knowingly maintained the hazardous overhead storage condition. 2015: $8.3 million EEOC settlement for race discrimination in hiring and termination. Lowe's contractor network: documented wage theft cases in California, New York, and other states have resulted in contractor settlements where Lowe's successfully maintained it bore no employer liability. Lowe's has faced class action litigation for misclassifying assistant managers as exempt from overtime.","flags":["1_6m_osha_bridgewater_nj_worker_death_2021","8_3m_eeoc_race_discrimination_2015","contractor_wage_theft_employer_liability_denied","assistant_manager_overtime_misclassification_class_actions"],"sources":["https://www.osha.gov/news/newsreleases/region2/03042021"]},"tax":{"summary":"Lowe's is a US-headquartered company paying US corporate taxes. Its Canadian operations (RONA acquisition) involve cross-border tax considerations. No major offshore tax enforcement or documented aggressive tax avoidance has been identified.","flags":["rona_canada_cross_border_considerations"],"sources":[]},"executives":{"summary":"CEO Marvin Ellison has led Lowe's since 2018 — one of the few Black CEOs of a Fortune 50 company. The 2021 OSHA settlement — for a worker who died due to a knowingly maintained hazard — occurred on his watch. The EEOC race discrimination settlement covered conduct predating his tenure.","flags":["ellison_black_ceo_fortune_50_rare","worker_death_osha_settlement_ellison_tenure"],"sources":[]},"connections":{"summary":"Lowe's and Home Depot together control the US home improvement retail market — effectively a duopoly with combined market share exceeding 80%. Both companies face the same contractor accountability gap, the same lumber sourcing deforestation concerns, and similar OSHA citation patterns.","flags":["home_depot_duopoly_parallel_contractor_issue","lumber_sourcing_shared_concern"],"sources":[]},"allegations":{"disclaimer":"The following are allegations and unproven claims documented in credible sources but not adjudicated.","summary":"OSHA investigators alleged in the Bridgewater, NJ case that store management was aware of the overhead storage hazard that killed the worker and had not corrected it despite having knowledge — making the violation 'willful' in OSHA's characterization. Worker advocacy organizations have alleged that Lowe's contractor referral model is deliberately structured to capture installation service revenue while denying the labor compliance obligations that a direct employment relationship would require.","flags":["willful_violation_management_awareness_alleged","deliberate_contractor_structure_labor_obligation_avoidance_alleged"],"sources":["https://www.osha.gov/news/newsreleases/region2/03042021"]},"health_record":{"summary":"The Bridgewater, NJ worker death — from a steel pipe falling from overhead storage — represents a direct occupational health failure at Lowe's. OSHA's finding that the condition was knowingly maintained intensifies the documented health failure. The pattern of OSHA citations across Lowe's stores for similar overhead storage, forklift, and egress hazards suggests systemic underinvestment in worker safety compliance.","flags":["worker_death_knowingly_maintained_hazard","systematic_overhead_storage_forklift_pattern"],"sources":[]},"alternatives":{"cheaper":["Home Depot — primary competitor with similar pricing and its own documented OSHA and contractor issues","Local hardware stores and lumber yards — often competitive on specific items with more direct accountability"],"healthier":["For contractor installation: verify any Lowe's-referred contractor license and insurance directly before engaging","Local union contractors for major renovation work — union membership implies some baseline labor standard adherence"],"diy":["For major lumber and wood product purchases: ask specifically for FSC-certified material — Lowe's carries FSC stock but it must be requested","OSHA's inspection records are publicly available — you can check whether your local Lowe's has received recent citations at osha.gov"]},"timeline":[{"year":2011,"event":"Lowe's pulls advertising from TLC's 'All-American Muslim' after pressure from advocacy group; controversy generates cross-spectrum criticism","severity":"moderate","source_url":""},{"year":2015,"event":"$8.3M EEOC race discrimination settlement for Black employee hiring and termination practices","severity":"high","source_url":""},{"year":2018,"event":"Marvin Ellison appointed CEO — one of few Black CEOs of a Fortune 50 company","severity":"neutral","source_url":""},{"year":2021,"event":"Bridgewater, NJ: worker killed by falling steel pipe; OSHA finds knowingly maintained hazard; $1.6M OSHA settlement","severity":"critical","source_url":"https://www.osha.gov/news/newsreleases/region2/03042021"},{"year":2022,"event":"Multiple state class action settlements for assistant manager overtime misclassification","severity":"high","source_url":""}],"community_impact":{"displacement":"The worker killed at Lowe's Bridgewater, NJ store — whose death OSHA found resulted from a knowingly maintained hazard — represents a community loss. Contractors in Lowe's referral network who engage in documented wage theft harm workers who perform installation labor in customers' homes while Lowe's captures the referral fee and denies employer responsibility.","price_illusion":"Lowe's installation service pricing — which is competitive — may embed the cost of contractor networks whose below-market labor includes documented wage theft that Lowe's structure denies responsibility for.","tax_math":"Lowe's pays standard US corporate taxes. The contractor misclassification — denying employer status for installation contractors — reduces Lowe's payroll tax obligations on the labor performing its installation services.","wealth_velocity":"Lowe's is publicly traded with broad institutional shareholder ownership. Revenue from installation services — where contractor labor costs may include documented wage theft that Lowe's denies responsibility for — flows to shareholders."},"cost_absorption":{"who_benefited":[{"group":"Lowe's shareholders","how":"Installation network revenue without employer cost obligations; contractor structure reduces labor compliance liability"}],"who_paid":[{"group":"Worker killed at Bridgewater, NJ","how":"Died from falling steel pipe in a condition Lowe's management knew was hazardous and had not corrected"},{"group":"Black employees subject to discrimination","how":"Employment opportunity denied or terminated on racial basis; $8.3M settlement"}],"the_gap":"A Lowe's worker died from a steel pipe that fell from overhead storage. OSHA found management knew the hazard existed and hadn't fixed it. The fine was $1.6 million. Lowe's paid $8.3 million for discriminating against Black employees. Their contractor referral network has documented wage theft. Lowe's says those workers aren't their employees. The customers who hired them thought they were using Lowe's."}});

